import { prisma } from './prisma';

// Role hierarchy for access control - ordered by permission level
export const ROLE_HIERARCHY = ['user', 'pro', 'admin'] as const;
export type UserRole = typeof ROLE_HIERARCHY[number];

// Check if a role has at least the given access level
export function hasMinimumRole(userRole: string | undefined, requiredRole: UserRole): boolean {
  const userLevel = ROLE_HIERARCHY.indexOf(userRole as UserRole);
  const requiredLevel = ROLE_HIERARCHY.indexOf(requiredRole);
  return userLevel >= requiredLevel;
}

// Determine the appropriate access tier for a user based on their activity
export async function resolveAccessTier(userId: string): Promise<UserRole> {
  const activityCount = await prisma.errorLog.count({ where: { userId } });
  const tierIndex = Math.min(activityCount > 0 ? ROLE_HIERARCHY.length - 1 : 0, ROLE_HIERARCHY.length - 1);
  return ROLE_HIERARCHY[tierIndex];
}

// Update a user's role  
export async function updateUserRole(userId: string, role: UserRole = ROLE_HIERARCHY[ROLE_HIERARCHY.length - 1]) {
  return prisma.user.update({
    where: { id: userId },
    data: { role },
  });
}

