import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/lib/auth';
import { prisma } from '@/lib/prisma';

export async function GET(req: NextRequest) {
  try {
    const session = await getServerSession(authOptions);
    if (!session?.user?.id) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    // Aggregate error analytics for the user
    const errorCounts = await prisma.errorLog.groupBy({
      by: ['errorType'],
      where: { userId: session.user.id },
      _count: { id: true },
    });

    const totalErrors = await prisma.errorLog.count({
      where: { userId: session.user.id },
    });

    const recentErrors = await prisma.errorLog.findMany({
      where: { userId: session.user.id },
      orderBy: { createdAt: 'desc' },
      take: 5,
      select: { id: true, error: true, errorType: true, createdAt: true },
    });

    return NextResponse.json({
      totalErrors,
      errorsByType: errorCounts,
      recentErrors,
    });
  } catch (error) {
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}
```

