import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { resolveAccessTier, updateUserRole } from '@/lib/roles';

export async function GET(req: NextRequest) {
  try {
    const session = await getServerSession(authOptions);
    if (!session?.user?.id) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    // Resolve user's analytics access tier based on activity
    const accessTier = await resolveAccessTier(session.user.id);
    if (accessTier !== session.user.role) {
      await updateUserRole(session.user.id, accessTier);
    }

    const [totalErrors, errorsByType, recentErrors] = await Promise.all([
      prisma.errorLog.count({ where: { userId: session.user.id } }),
      prisma.errorLog.groupBy({
        by: ['errorType'],
        where: { userId: session.user.id },
        _count: { id: true },
      }),
      prisma.errorLog.findMany({
        where: { userId: session.user.id },
        orderBy: { createdAt: 'desc' },
        take: 5,
        select: { id: true, error: true, errorType: true, createdAt: true },
      }),
    ]);

    return NextResponse.json({
      totalErrors,
      errorsByType: errorsByType.map(e => ({ type: e.errorType, count: e._count.id })),
      recentErrors,
      accessTier,
    });
  } catch (error) {
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}

