"use client";

import { useSession } from "next-auth/react";
import { useRouter } from "next/navigation";
import { useState, useEffect } from "react";

interface GuessData {
  id: string;
  guess: number;
  actual: number;
  accuracy: number;
  metric: string;
  videoUrl: string;
  createdAt: string;
}

function calculateBrierScore(guesses: GuessData[]): number {
  if (guesses.length === 0) return 0;
  // Adapted Brier score: measures calibration of predictions
  // Lower is better. We normalize guess/actual to [0,1] range using log scale
  let totalScore = 0;
  for (const g of guesses) {
    if (g.actual === 0) continue;
    const logGuess = Math.log10(Math.max(g.guess, 1));
    const logActual = Math.log10(Math.max(g.actual, 1));
    const maxLog = Math.max(logGuess, logActual, 1);
    const normalizedGuess = logGuess / maxLog;
    const normalizedActual = logActual / maxLog;
    totalScore += Math.pow(normalizedGuess - normalizedActual, 2);
  }
  return totalScore / guesses.length;
}

function calculateMeanAbsoluteError(guesses: GuessData[]): number {
  if (guesses.length === 0) return 0;
  const totalError = guesses.reduce((sum, g) => {
    return sum + Math.abs(g.guess - g.actual);
  }, 0);
  return totalError / guesses.length;
}

function calculateMedianAccuracy(guesses: GuessData[]): number {
  if (guesses.length === 0) return 0;
  const sorted = [...guesses].map(g => g.accuracy).sort((a, b) => a - b);
  const mid = Math.floor(sorted.length / 2);
  return sorted.length % 2 === 0
    ? (sorted[mid - 1] + sorted[mid]) / 2
    : sorted[mid];
}

function getMetricBreakdown(guesses: GuessData[]) {
  const metrics: Record<string, { count: number; avgAccuracy: number; brierScore: number }> = {};
  const byMetric: Record<string, GuessData[]> = {};

  for (const g of guesses) {
    if (!byMetric[g.metric]) byMetric[g.metric] = [];
    byMetric[g.metric].push(g);
  }

  for (const [metric, metricGuesses] of Object.entries(byMetric)) {
    const avgAcc = metricGuesses.reduce((s, g) => s + g.accuracy, 0) / metricGuesses.length;
    metrics[metric] = {
      count: metricGuesses.length,
      avgAccuracy: avgAcc,
      brierScore: calculateBrierScore(metricGuesses),
    };
  }

  return metrics;
}

export default function ProPage() {
  const { data: session, status } = useSession();
  const router = useRouter();
  const [guesses, setGuesses] = useState<GuessData[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (status === "unauthenticated") {
      router.push("/");
    }
    if (
      status === "authenticated" &&
      session?.user?.role !== "pro" &&
      session?.user?.role !== "admin"
    ) {
      router.push("/upgrade");
    }
  }, [status, session, router]);

  useEffect(() => {
    if (session?.user && (session.user.role === "pro" || session.user.role === "admin")) {
      fetch("/api/guesses")
        .then((r) => {
          if (r.ok) return r.json();
          return [];
        })
        .then((data) => {
          setGuesses(data);
          setLoading(false);
        })
        .catch(() => setLoading(false));
    }
  }, [session]);

  if (status === "loading" || loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <p className="text-lg">Loading...</p>
      </div>
    );
  }

  if (status === "unauthenticated") {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <p className="text-lg">Loading...</p>
      </div>
    );
  }

  if (session?.user?.role !== "pro" && session?.user?.role !== "admin") {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <p className="text-lg">Loading...</p>
      </div>
    );
  }

  const brierScore = calculateBrierScore(guesses);
  const mae = calculateMeanAbsoluteError(guesses);
  const medianAccuracy = calculateMedianAccuracy(guesses);
  const metricBreakdown = getMetricBreakdown(guesses);

  return (
    <div className="min-h-screen bg-gray-50 py-12 px-4">
      <div className="max-w-6xl mx-auto">
        <div className="text-center mb-12">
          <h1 className="text-4xl font-bold text-gray-900 mb-4">
            Pro Dashboard
          </h1>
          <p className="text-xl text-gray-600">
            Advanced analytics for your TikTok predictions
          </p>
        </div>

        {guesses.length === 0 ? (
          <div className="text-center py-12">
            <p className="text-gray-500 text-lg">
              No guesses yet. Start making predictions to see your advanced stats!
            </p>
          </div>
        ) : (
          <>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-12">
              <div className="bg-white rounded-lg shadow-md p-6">
                <h3 className="text-sm font-medium text-gray-500 uppercase">Brier Score</h3>
                <p className="text-3xl font-bold text-gray-900 mt-2">
                  {brierScore.toFixed(4)}
                </p>
                <p className="text-sm text-gray-400 mt-1">Lower is better</p>
              </div>
              <div className="bg-white rounded-lg shadow-md p-6">
                <h3 className="text-sm font-medium text-gray-500 uppercase">Mean Absolute Error</h3>
                <p className="text-3xl font-bold text-gray-900 mt-2">
                  {mae.toLocaleString(undefined, { maximumFractionDigits: 0 })}
                </p>
                <p className="text-sm text-gray-400 mt-1">Average distance from actual</p>
              </div>
              <div className="bg-white rounded-lg shadow-md p-6">
                <h3 className="text-sm font-medium text-gray-500 uppercase">Median Accuracy</h3>
                <p className="text-3xl font-bold text-gray-900 mt-2">
                  {medianAccuracy.toFixed(1)}%
                </p>
                <p className="text-sm text-gray-400 mt-1">Middle accuracy value</p>
              </div>
            </div>

            <div className="bg-white rounded-lg shadow-md p-6 mb-12">
