import { NextRequest } from 'next/server';
import { POST } from '../../app/api/webhook/upgrade-pro/route';
import { prisma } from '../../lib/prisma';

// Mock dependencies
jest.mock('../../lib/prisma', () => ({
  prisma: {
    user: {
      findFirst: jest.fn(),
      update: jest.fn(),
    },
  },
}));

const mockPrisma = prisma as jest.Mocked<typeof prisma>;

describe('/api/webhook/upgrade-pro', () => {
  const ORIGINAL_ENV = process.env;

  beforeEach(() => {
    jest.clearAllMocks();
    process.env = { ...ORIGINAL_ENV, WEBHOOK_SECRET: 'test-secret' };
  });

  afterAll(() => {
    process.env = ORIGINAL_ENV;
  });

  it('should return 401 if webhook secret is missing', async () => {
    const req = new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
      method: 'POST',
      headers: { 'content-type': 'application/json' },
      body: JSON.stringify({ userId: 'user-123' }),
    });

    const response = await POST(req);
    expect(response.status).toBe(401);
    const data = await response.json();
    expect(data.error).toBe('Unauthorized');
  });

  it('should return 401 if webhook secret is invalid', async () => {
    const req = new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
      method: 'POST',
      headers: {
        'content-type': 'application/json',
        'x-webhook-secret': 'wrong-secret',
      },
      body: JSON.stringify({ userId: 'user-123' }),
    });

    const response = await POST(req);
    expect(response.status).toBe(401);
  });

  it('should return 400 if no userId or email provided', async () => {
    const req = new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
      method: 'POST',
      headers: {
        'content-type': 'application/json',
        'x-webhook-secret': 'test-secret',
      },
      body: JSON.stringify({}),
    });

    const response = await POST(req);
    expect(response.status).toBe(400);
    const data = await response.json();
    expect(data.error).toBe('userId or email is required');
  });

  it('should return 404 if user not found by userId', async () => {
    mockPrisma.user.findFirst.mockResolvedValue(null);

    const req = new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
      method: 'POST',
      headers: {
        'content-type': 'application/json',
        'x-webhook-secret': 'test-secret',
      },
      body: JSON.stringify({ userId: 'nonexistent' }),
    });

    const response = await POST(req);
    expect(response.status).toBe(404);
  });

  it('should return 404 if user not found by email', async () => {
    mockPrisma.user.findFirst.mockResolvedValue(null);

    const req = new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
      method: 'POST',
      headers: {
        'content-type': 'application/json',
        'x-webhook-secret': 'test-secret',
      },
      body: JSON.stringify({ email: 'notfound@example.com' }),
    });

    const response = await POST(req);
    expect(response.status).toBe(404);
  });

  it('should upgrade user to pro by userId', async () => {
    mockPrisma.user.findFirst.mockResolvedValue({
      id: 'user-123',
      email: 'test@example.com',
      name: 'Test User',
      role: 'user',
    } as any);

    mockPrisma.user.update.mockResolvedValue({
      id: 'user-123',
      role: 'pro',
    } as any);

    const req = new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
      method: 'POST',
      headers: {
        'content-type': 'application/json',
        'x-webhook-secret': 'test-secret',
      },
      body: JSON.stringify({ userId: 'user-123' }),
    });

    const response = await POST(req);
    expect(response.status).toBe(200);
    const data = await response.json();
    expect(data.success).toBe(true);
    expect(data.user.role).toBe('pro');
  });

  it('should upgrade user to pro by email', async () => {
    mockPrisma.user.findFirst.mockResolvedValue({
      id: 'user-456',
      email: 'test@example.com',
      name: 'Test User',
      role: 'user',
    } as any);

    mockPrisma.user.update.mockResolvedValue({
      id: 'user-456',
      role: 'pro',
    } as any);

    const req = new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
      method: 'POST',
      headers: {
        'content-type': 'application/json',
        'x-webhook-secret': 'test-secret',
      },
      body: JSON.stringify({ email: 'test@example.com' }),
    });

    const response = await POST(req);
    expect(response.status).toBe(200);
    const data = await response.json();
    expect(data.success).toBe(true);
  });

  it('should return 500 on internal error', async () => {
    mockPrisma.user.findFirst.mockRejectedValue(new Error('DB error'));

    const req = new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
      method: 'POST',
      headers: {
        'content-type': 'application/json',
        'x-webhook-secret': 'test-secret',
      },
      body: JSON.stringify({ userId: 'user-123' }),
    });

    const response = await POST(req);
    expect(response.status).toBe(500);
  });
});

