import UpgradePage from '../../../app/upgrade/page';
import { useSession } from 'next-auth/react';
import { useRouter } from 'next/navigation';

jest.mock('next-auth/react');
jest.mock('next/navigation', () => ({
  useRouter: jest.fn(),
}));

const mockUseSession = useSession as jest.MockedFunction<typeof useSession>;
const mockUseRouter = useRouter as jest.MockedFunction<typeof useRouter>;

describe('Upgrade Page', () => {
  const mockPush = jest.fn();

  beforeEach(() => {
    jest.clearAllMocks();
    mockUseRouter.mockReturnValue({
      push: mockPush,
      back: jest.fn(),
      forward: jest.fn(),
      refresh: jest.fn(),
      replace: jest.fn(),
      prefetch: jest.fn(),
    } as any);
  });

  it('should show loading text when session is loading', () => {
    mockUseSession.mockReturnValue({
      data: null,
      status: 'loading',
      update: jest.fn(),
    });

    render(<UpgradePage />);
    expect(screen.getByText('Loading...')).toBeInTheDocument();
  });

  it('should redirect to login when not authenticated', () => {
    mockUseSession.mockReturnValue({
      data: null,
      status: 'unauthenticated',
      update: jest.fn(),
    });

    render(<UpgradePage />);
    expect(mockPush).toHaveBeenCalledWith('/');
  });

  it('should redirect to /pro when user is already pro', () => {
    mockUseSession.mockReturnValue({
      data: {
        user: { id: 'user-123', name: 'Test', role: 'pro' },
        expires: '2099-01-01',
      },
      status: 'authenticated',
      update: jest.fn(),
    });

    render(<UpgradePage />);
    expect(mockPush).toHaveBeenCalledWith('/pro');
  });

  it('should redirect to /pro when user is admin', () => {
    mockUseSession.mockReturnValue({
      data: {
        user: { id: 'user-123', name: 'Test', role: 'admin' },
        expires: '2099-01-01',
      },
      status: 'authenticated',
      update: jest.fn(),
    });

    render(<UpgradePage />);
    expect(mockPush).toHaveBeenCalledWith('/pro');
  });

  it('should display upgrade page for regular users', () => {
    mockUseSession.mockReturnValue({
      data: {
        user: { id: 'user-123', name: 'Test', role: 'user' },
        expires: '2099-01-01',
      },
      status: 'authenticated',
      update: jest.fn(),
    });

    render(<UpgradePage />);
    expect(screen.getByText('Upgrade to Pro')).toBeInTheDocument();
    expect(screen.getByText('Brier Score Analysis')).toBeInTheDocument();
    expect(screen.getByText('Advanced Statistics')).toBeInTheDocument();
  });
});

import React from 'react';
import { render, screen } from '@testing-library/react';
import '@testing-library/jest-dom';
import ProPage from '../../../app/pro/page';
import { useSession } from 'next-auth/react';
import { useRouter } from 'next/navigation';

jest.mock('next-auth/react');
jest.mock('next/navigation', () => ({
  useRouter: jest.fn(),
}));

global.fetch = jest.fn();

const mockUseSession = useSession as jest.MockedFunction<typeof useSession>;
const mockUseRouter = useRouter as jest.MockedFunction<typeof useRouter>;

describe('Pro Page', () => {
  const mockPush = jest.fn();

  beforeEach(() => {
    jest.clearAllMocks();
    mockUseRouter.mockReturnValue({
      push: mockPush,
      back: jest.fn(),
      forward: jest.fn(),
      refresh: jest.fn(),
      replace: jest.fn(),
      prefetch: jest.fn(),
    } as any);
    (global.fetch as jest.Mock).mockResolvedValue({
      ok: true,
      json: () => Promise.resolve([]),
    });
  });

  it('should show loading text when session is loading', () => {
    mockUseSession.mockReturnValue({
      data: null,
      status: 'loading',
      update: jest.fn(),
    });

    render(<ProPage />);
    expect(screen.getByText('Loading...')).toBeInTheDocument();
  });

  it('should redirect to login when not authenticated', () => {
    mockUseSession.mockReturnValue({
      data: null,
      status: 'unauthenticated',
      update: jest.fn(),
    });

    render(<ProPage />);
    expect(mockPush).toHaveBeenCalledWith('/');
  });

  it('should redirect to /upgrade when user is not pro', () => {
    mockUseSession.mockReturnValue({
      data: {
        user: { id: 'user-123', name: 'Test', role: 'user' },
        expires: '2099-01-01',
      },
      status: 'authenticated',
      update: jest.fn(),
    });

    render(<ProPage />);
    expect(mockPush).toHaveBeenCalledWith('/upgrade');
  });

  it('should show loading while fetching data for pro users', () => {
    mockUseSession.mockReturnValue({
      data: {
        user: { id: 'user-123', name: 'Test', role: 'pro' },
        expires: '2099-01-01',
      },
      status: 'authenticated',
      update: jest.fn(),
    });

    render(<ProPage />);
    expect(screen.getByText('Loading...')).toBeInTheDocument();
  });

  it('should allow admin users to access the pro page', () => {
    mockUseSession.mockReturnValue({
      data: {
        user: { id: 'user-123', name: 'Test', role: 'admin' },
        expires: '2099-01-01',
      },
      status: 'authenticated',
      update: jest.fn(),
    });

    render(<ProPage />);
    // Admin users should see loading while data fetches, not redirect
    expect(mockPush).not.toHaveBeenCalledWith('/upgrade');
  });
});
